    <div class="card-body">
        <EditForm Model="newShipment" OnValidSubmit="Submit" FormName="createShipment">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" />

            <div class="mb-3">
                <label class="form-label">Tracking Number</label>
                <InputText class="form-control" @bind-Value="newShipment.TrackingNumber" placeholder="TRK-XXX-2026" />
            </div>

            <div class="mb-3">
                <label class="form-label">Description</label>
                <InputText class="form-control" @bind-Value="newShipment.Description" placeholder="Package contents" />
            </div>

            <div class="row mb-3">
                <div class="col">
                    <label class="form-label">Origin</label>
                    <InputText class="form-control" @bind-Value="newShipment.Origin" placeholder="City, Country" />
                </div>
                <div class="col">
                    <label class="form-label">Destination</label>
                    <InputText class="form-control" @bind-Value="newShipment.Destination" placeholder="City, Country" />
                </div>
            </div>

            <div class="row mb-3">
                <div class="col">
                    <label class="form-label">Shipped Date</label>
                    <InputDate class="form-control" @bind-Value="newShipment.ShippedDate" />
                </div>
                <div class="col">
                    <label class="form-label">Est. Delivery</label>
                    <InputDate class="form-control" @bind-Value="newShipment.EstimatedDelivery" />
                </div>
            </div>

            <div class="mb-3">
                <label class="form-label">Customer Email</label>
                <InputText class="form-control" @bind-Value="newShipment.CustomerEmail" type="email" placeholder="customer@example.com" />
            </div>

            <div class="mb-3">
                <label class="form-label">Status</label>
                <InputSelect class="form-select" @bind-Value="newShipment.Status">
                    @foreach (var status in Enum.GetValues<ShipmentStatus>())
                    {
                        <option value="@status">@status</option>
                    }
                </InputSelect>
            </div>

            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger">@errorMessage</div>
            }

            <button type="submit" class="btn btn-success" disabled="@isSubmitting">
                @(isSubmitting ? "Creating..." : "Create Shipment")
            </button>
            <a href="/shipments" class="btn btn-outline-secondary ms-2">Cancel</a>
        </EditForm>
    </div>
</div>

@code {
    private ShipmentDto newShipment = new()
    {
        ShippedDate = DateTime.UtcNow,
